INSERT INTO contract_templates (contract_type, jurisdiction, version, title, preamble, recitals, clauses, signature_block, placeholders, is_active, metadata) VALUES (
  'independent_contractor',
  'uk',
  1,
  'Consultancy Agreement (United Kingdom)',
  'This Consultancy Agreement (the "Agreement") is entered into as of {{effective_date}} (the "Effective Date"), by and between {{party_a_company}}, a company registered in England and Wales with registered address at {{party_a_address}} ("Client"), and {{party_b_company}}, with address at {{party_b_address}} ("Consultant"). Client and Consultant may be referred to individually as a "Party" and collectively as the "Parties".',
  'WHEREAS, Client desires to engage Consultant to perform certain consultancy services described in this Agreement; and
WHEREAS, Consultant represents that Consultant has the expertise, resources, and ability to perform such services as an independent contractor;
NOW, THEREFORE, in consideration of the mutual covenants and promises contained herein, the Parties agree as follows:',
  '[{"id":"services","title":"1. SERVICES","content":"1.1 Services. Consultant shall perform the services described in {{services_description}} (the \"Services\") in a professional manner, consistent with generally accepted industry standards and using reasonable skill and care.\n\n1.2 Deliverables; Schedule. Any deliverables, milestones, deadlines, and acceptance criteria shall be as specified in {{services_description}} or as otherwise agreed in writing by the Parties.\n\n1.3 Place and Manner of Performance. Consultant will determine the method, details, and means of performing the Services; provided that Consultant shall reasonably cooperate with Client''s operational and security policies when accessing Client''s facilities, systems, or personnel.\n\n1.4 Changes. Client may request changes to the scope of Services. Any material change affecting scope, timeline, or fees must be agreed to in writing by both Parties.\n\n1.5 No Authority. Consultant has no authority to bind Client, incur obligations on Client''s behalf, or make representations as an agent of Client unless expressly authorised in writing.","type":"standard","order":1},{"id":"compensation","title":"2. FEES; INVOICING; EXPENSES","content":"2.1 Fees. As full consideration for the Services, Client shall pay Consultant as follows: (a) a total fee of {{payment_amount}} and/or (b) a day rate or hourly rate of {{hourly_rate}}, as applicable to the Services described in {{services_description}}.\n\n2.2 Invoicing and Payment. Consultant shall invoice Client in accordance with the invoicing schedule stated in {{services_description}}. Unless otherwise stated, Client shall pay undisputed amounts within 30 days of receipt of a valid invoice.\n\n2.3 Expenses. Unless expressly authorised in advance in writing by Client, Consultant is responsible for all expenses incurred in performing the Services. Any pre-approved reimbursable expenses must be supported by reasonable documentation.\n\n2.4 VAT. All fees are exclusive of Value Added Tax (VAT). If VAT is applicable, Consultant shall add VAT at the prevailing rate to invoices, and Client shall pay such VAT.\n\n2.5 Taxes. Consultant is solely responsible for all taxes, National Insurance contributions, and other governmental charges arising from fees paid under this Agreement. Client will not withhold PAYE or make employer National Insurance contributions for Consultant.\n\n2.6 No Employee Benefits. Consultant acknowledges that Consultant is not eligible for Client-provided employee benefits, including holiday pay, sick pay, pension contributions, or other employment benefits.","type":"standard","order":2},{"id":"consultant_status_ir35","title":"3. CONSULTANT STATUS; IR35 COMPLIANCE","content":"3.1 Independent Contractor. Consultant is engaged as an independent contractor and not as an employee, worker, partner, or agent of Client. Consultant shall control the manner and means of performing the Services, subject only to the requirements of this Agreement.\n\n3.2 No Employment Relationship. Nothing in this Agreement shall be construed to create an employment relationship. Consultant shall not represent that Consultant is an employee of Client.\n\n3.3 IR35 Considerations. The Parties intend that the engagement under this Agreement falls outside the scope of the off-payroll working rules (commonly known as \"IR35\") set out in Chapter 10 of Part 2 of the Income Tax (Earnings and Pensions) Act 2003. Consultant represents and warrants that Consultant has considered the nature of this engagement and believes that IR35 does not apply. If Client is a medium or large business and required to make a Status Determination Statement (SDS) under the off-payroll working rules, the Parties shall cooperate in good faith to determine the correct status. If the engagement is determined to be within IR35, the Parties shall discuss appropriate adjustments.\n\n3.4 Substitution. Consultant may, with Client''s prior written consent (not to be unreasonably withheld), provide a suitably qualified substitute to perform the Services. Consultant shall remain responsible for the substitute''s performance and compliance with this Agreement.\n\n3.5 Consultant''s Business. Consultant is responsible for providing tools, equipment, and materials necessary to perform the Services, maintaining any required business registrations and insurance, and operating Consultant''s business in compliance with applicable law.\n\n3.6 Non-Exclusivity. Unless otherwise stated, Consultant may perform services for others during the Term, provided such services do not materially interfere with Consultant''s performance or breach this Agreement.","type":"standard","order":3},{"id":"term_termination","title":"4. TERM; TERMINATION","content":"4.1 Term. This Agreement begins on the Effective Date and continues until {{expiration_date}}, unless earlier terminated in accordance with this Section (the \"Term\"). If no expiration date is specified, the Term shall continue until completion of the Services or termination as provided herein.\n\n4.2 Termination for Convenience. Either Party may terminate this Agreement for any reason upon written notice at least {{notice_period}} days prior to the effective termination date.\n\n4.3 Termination for Cause. Either Party may terminate immediately upon written notice if the other Party: (a) materially breaches this Agreement and fails to remedy such breach within 14 days after receiving written notice; (b) becomes insolvent or enters into administration, liquidation, or similar proceedings; or (c) engages in fraud or gross misconduct.\n\n4.4 Effect of Termination. Upon termination: (a) Consultant shall stop work except as necessary to wind down; (b) Consultant shall deliver to Client all Client property and Work Product created through the termination date; and (c) Client shall pay Consultant for Services properly performed through the termination date.\n\n4.5 Survival. Sections intended to survive shall survive termination, including Sections 5 (Intellectual Property), 6 (Confidentiality), 7 (Warranties), and 8 (Liability).","type":"standard","order":4},{"id":"intellectual_property","title":"5. INTELLECTUAL PROPERTY; WORK PRODUCT","content":"5.1 Definitions. \"Work Product\" means all deliverables, work product, inventions, discoveries, developments, designs, works of authorship, documentation, reports, software, and other materials created by Consultant in connection with the Services.\n\n5.2 Ownership; Assignment. Client shall own all right, title, and interest in the Work Product. Consultant hereby assigns (and agrees to assign) to Client all rights in the Work Product, including all intellectual property rights, to the fullest extent permitted by law.\n\n5.3 Further Assurance. Consultant shall execute such documents and take such actions as Client may reasonably request to perfect Client''s rights in the Work Product.\n\n5.4 Consultant Background IP. \"Background IP\" means intellectual property owned or developed by Consultant outside the scope of this Agreement. Consultant retains all rights in Background IP. To the extent Consultant incorporates Background IP into the Work Product, Consultant grants Client a perpetual, irrevocable, worldwide, royalty-free, transferable, and sublicensable licence to use such Background IP as part of the Work Product.\n\n5.5 Moral Rights. To the extent permitted by law, Consultant waives any moral rights in the Work Product under the Copyright, Designs and Patents Act 1988.\n\n5.6 No Restriction on Lawful Activities. Nothing in this Agreement prevents Consultant from engaging in any lawful profession or business, subject to confidentiality and non-solicitation obligations.","type":"negotiable","order":5},{"id":"confidentiality","title":"6. CONFIDENTIALITY; DATA PROTECTION","content":"6.1 Confidential Information. \"Confidential Information\" means any non-public information disclosed by Client to Consultant that is designated as confidential or that reasonably should be understood to be confidential. This includes business, financial, customer, technical, and trade secret information.\n\n6.2 Confidentiality Obligations. Consultant shall: (a) use Confidential Information solely to perform the Services; (b) protect Confidential Information using reasonable care; (c) not disclose Confidential Information except to personnel bound by confidentiality obligations; and (d) promptly notify Client of any suspected unauthorised disclosure.\n\n6.3 Exclusions. Confidential Information excludes information that: (a) is publicly available; (b) was known to Consultant before disclosure; (c) is received from a third party without confidentiality restrictions; or (d) is independently developed.\n\n6.4 Return/Destruction. Upon request or termination, Consultant shall return or destroy all Confidential Information.\n\n6.5 Data Protection. To the extent Consultant processes Personal Data (as defined in the UK GDPR) on behalf of Client: (a) Consultant shall process such data only for the purposes of performing the Services; (b) Consultant shall implement appropriate technical and organisational measures; (c) Consultant shall not transfer Personal Data outside the UK unless permitted by law; and (d) the Parties shall, if required, enter into appropriate data processing terms.","type":"standard","order":6},{"id":"warranties","title":"7. WARRANTIES","content":"7.1 Mutual Authority. Each Party represents that it has authority to enter into this Agreement.\n\n7.2 Consultant Warranties. Consultant represents and warrants that: (a) Consultant has the skill and experience to perform the Services; (b) the Services will be performed with reasonable skill and care; (c) Consultant will comply with applicable laws; (d) the Work Product will not infringe third-party intellectual property rights; and (e) Consultant will not introduce malicious code into Client''s systems.\n\n7.3 Disclaimer. Except as expressly stated, neither Party makes any other warranties, including implied warranties of merchantability or fitness for a particular purpose, to the maximum extent permitted by law.","type":"standard","order":7},{"id":"liability","title":"8. LIABILITY","content":"8.1 Consultant Liability. Consultant shall be liable for losses arising from Consultant''s breach of this Agreement, negligence, or wilful misconduct.\n\n8.2 Limitation of Liability. Subject to Section 8.3, neither Party shall be liable for any indirect, consequential, or special damages (including lost profits) arising from this Agreement. Total liability under this Agreement shall not exceed the greater of (a) the total fees paid or payable under this Agreement in the 12 months preceding the claim, or (b) £{{liability_cap}}.\n\n8.3 Unlimited Liability. Nothing in this Agreement limits liability for: (a) death or personal injury caused by negligence; (b) fraud or fraudulent misrepresentation; (c) any liability which cannot be limited by law; or (d) breaches of Section 5 (Intellectual Property) or Section 6 (Confidentiality).\n\n8.4 Insurance. Consultant shall maintain appropriate professional indemnity insurance and, if applicable, public liability insurance.","type":"negotiable","order":8},{"id":"governing_law","title":"9. GOVERNING LAW; JURISDICTION","content":"9.1 Governing Law. This Agreement shall be governed by the law of England and Wales.\n\n9.2 Jurisdiction. The courts of England and Wales shall have exclusive jurisdiction over any dispute, except that either Party may seek injunctive relief in any court of competent jurisdiction.","type":"standard","order":9},{"id":"general_provisions","title":"10. GENERAL PROVISIONS","content":"10.1 Notices. Notices must be in writing and delivered personally, by courier, by Royal Mail signed-for delivery, or by email.\n\n10.2 Assignment. Consultant may not assign this Agreement without Client''s prior written consent. Client may assign in connection with a merger or acquisition.\n\n10.3 Subcontracting. Consultant may not subcontract without Client''s prior written consent. Consultant remains responsible for subcontractors.\n\n10.4 Relationship. The Parties are independent contractors. No partnership, joint venture, or employment relationship is created.\n\n10.5 Compliance. Each Party shall comply with applicable laws.\n\n10.6 Severability. Invalid provisions shall be modified to the minimum extent necessary.\n\n10.7 Waiver. Waivers must be in writing.\n\n10.8 Entire Agreement. This Agreement constitutes the entire agreement. Amendments require written agreement signed by both Parties.\n\n10.9 Counterparts. May be executed in counterparts, including electronically under the Electronic Communications Act 2000.\n\n10.10 Third Party Rights. No third party rights under the Contracts (Rights of Third Parties) Act 1999.\n\n10.11 Force Majeure. Neither Party is liable for delays due to causes beyond reasonable control.\n\n10.12 Anti-Bribery. Each Party shall comply with the Bribery Act 2010 and shall not engage in any activity that would constitute a bribery offence.","type":"standard","order":10}]'::jsonb,
  'IN WITNESS WHEREOF, the Parties have executed this Agreement as of {{signature_date}}.

